{
  "id": "behavioral_008",
  "question": "Describe a leadership experience.",
  "star_answer": {
    "situation": "As the Unlox Campus Ambassador at Amrita University, I was responsible for driving student engagement and organizing workshops on technical skills.",
    "task": "I had to organize a workshop on web development and API integration for students who had varying levels of programming experience.",
    "action": "I designed the curriculum around building a real project\u2014a weather app\u2014rather than lecturing on syntax. I paired students with more coding experience with beginners. I also set up a GitHub repository with template branches so that students who fell behind could jump to a working checkpoint.",
    "result": "Over 50 students attended, and every single participant successfully built and deployed a working web application by the end of the session.",
    "learning": "Leadership is about creating the infrastructure for others to succeed. Clear organization, templates, and peer-matching build far more competence than loud charisma."
  }
}
